const CONNECTION_TYPE = env.get('CONNECTION_TYPE');
const RETENTION_MS = env.get('RETENTION_MS') || 0;
const POLL_INTERVAL_MS = 500;
const PREFIX = env.get('CONTEXT_PREFIX') || '';

const formatStatus = global.get('utils.formatStatus', 'initializers');
const state = global.get(`connections.${CONNECTION_TYPE}`);

// OPEN GATE - Immediate passthrough
if (state !== 'down') {
    node.status({ fill: 'green', shape: 'dot', text: formatStatus('PASSTHROUGH') });
    return [msg, null];
}

// CLOSED GATE - NO RETENTION - Immediate drop
if (!RETENTION_MS) {
    node.status({ fill: 'red', shape: 'dot', text: formatStatus('DROPPED') });
    return [null, msg];
}

// CLOSED GATE - WITH RETENTION - Poll for disposition
const existing = flow.get(`${PREFIX}retention_poll`, 'volatile');
if (existing) {
    clearInterval(existing);
    flow.set(`${PREFIX}retention_poll`, null, 'volatile');
}

let elapsed = 0;
const snapshot = msg;

node.status({ fill: 'yellow', shape: 'ring', text: formatStatus('WAITING') });

const pollId = setInterval(() => {
    elapsed += POLL_INTERVAL_MS;
    const currentState = global.get(`connections.${CONNECTION_TYPE}`);

    // GATE OPENED WITHIN RETENTION - Passthrough as recovered.
    if (currentState !== 'down') {
        clearInterval(flow.get(`${PREFIX}retention_poll`, 'volatile'));
        flow.set(`${PREFIX}retention_poll`, null, 'volatile');
        node.status({ fill: 'green', shape: 'ring', text: formatStatus('RECOVERED') });
        node.send([snapshot, null]);
        return;
    }

    // GATE CLOSED AT EXPIRATION - Dropped as expired.
    if (elapsed >= RETENTION_MS) {
        clearInterval(flow.get(`${PREFIX}retention_poll`, 'volatile'));
        flow.set(`${PREFIX}retention_poll`, null, 'volatile');
        node.status({ fill: 'red', shape: 'ring', text: formatStatus('EXPIRED') });
        node.send([null, snapshot]);
    }
}, POLL_INTERVAL_MS);

flow.set(`${PREFIX}retention_poll`, pollId, 'volatile');
return null;

msg.payload = {
    fill: msg.status.fill,
    shape: msg.status.shape,
    text: msg.status.text
};

return msg;

const prefix = env.get('CONTEXT_PREFIX') || '';

if (flow.get(`${prefix}initialized`)) {
    return [msg, null];
}
if (flow.get(`${prefix}degraded`)) {
    return null;
}
const buffer = flow.get(`${prefix}state_buffer`) || [];
buffer.push(msg);
flow.set(`${prefix}state_buffer`, buffer);
if (!flow.get(`${prefix}check_running`)) {
    flow.set(`${prefix}check_running`, true);
    flow.set(`${prefix}retries`, 0);
    return [null, msg];
}

return null;

const prefix = env.get('CONTEXT_PREFIX') || '';
const maxRetries = env.get('MAX_RETRIES') || 20;
const retries = flow.get(`${prefix}retries`) || 0;

if (global.get('initializers.ready', 'initializers') === true) {
    flow.set(`${prefix}check_running`, false);
    return [msg, null];
}
if (retries >= maxRetries) {
    flow.set(`${prefix}check_running`, false);
    msg.timedOut = true;
    return [null, msg];
}
flow.set(`${prefix}retries`, retries + 1);
return [null, msg];

const prefix = env.get('CONTEXT_PREFIX') || '';
flow.set(`${prefix}initialized`, true);
flow.set(`${prefix}degraded`, false);
flow.set(`${prefix}check_running`, false);

const buffer = flow.get(`${prefix}state_buffer`) || [];
flow.set(`${prefix}state_buffer`, []);

for (const bufferedMsg of buffer) {
    node.send([bufferedMsg, null]);
}

const prefix = env.get('CONTEXT_PREFIX') || '';
flow.set(`${prefix}degraded`, true);
flow.set(`${prefix}initialized`, false);
flow.set(`${prefix}check_running`, false);
flow.set(`${prefix}state_buffer`, []);

msg.timedOut = true;
return msg;

const required = ['targets', 'severity', 'title', 'message'];
const missing = required.filter(f => !msg.payload[f]);

if (missing.length > 0) {
    node.warn(`Notification dropped — missing required fields: ${missing.join(', ')}`);
    return null;
}

if (!Array.isArray(msg.payload.targets) || msg.payload.targets.length === 0) {
    node.warn('Notification dropped — targets must be a non-empty array');
    return null;
}

return msg;

const notifications = global.get('config').notifications;
const { targets } = msg.payload;

for (const target of targets) {
    const parts = target.split('.');
    if (parts.length !== 3) {
        node.warn(`Invalid target format: ${target}`);
        continue;
    }
    const [namespace, key, channel] = parts;
    const section = notifications[namespace];
    if (!section) {
        node.warn(`Unknown namespace: ${namespace}`);
        continue;
    }
    const keys = key === '*' ? Object.keys(section) : [key];
    for (const k of keys) {
        const entry = section[k];
        if (!entry) {
            node.warn(`Unknown ${namespace} key: ${k}`);
            continue;
        }
        const address = entry.channels?.[channel];
        if (!address) {
            node.warn(`No channel '${channel}' for ${namespace}.${k}`);
            continue;
        }
        node.send({
            payload: {
                ...msg.payload,
                _delivery: { namespace, key: k, channel, address }
            },
            target: resolveLinkTarget(channel)
        });
    }
}
return null;

function resolveLinkTarget(channel) {
    switch (channel) {
        case 'ha_companion': return 'Home Assistant Companion';
        case 'tv':           return 'Television Routing';
        default: throw new Error(`Unable to resolve channel: ${channel}`);
    }
}

const { _delivery } = msg.payload;

// Clear path
if (_delivery.type === 'clear') {
    msg.payload = {
        action: _delivery.address,
        data: {
            message: 'clear_notification',
            data: { tag: msg.payload.correlation_id }
        }
    };
    msg.log_message = `Notification cleared for ${_delivery.recipient} via ${_delivery.channel}`;
    return msg;
}

// Delivery path
const { severity, title, message,
        sticky, group, correlation_id,
        dnd_override, media, actionable, actions,url } = msg.payload;

const channelMap = {
    low:      'highland_low',
    medium:   'highland_default',
    high:     'highland_high',
    critical: 'highland_critical'
};

const persistentMap = {
    low: false, medium: false, high: false, critical: true
};

const data = {
    channel:    channelMap[severity] || 'highland_default',
    importance: severity === 'low' ? 'low' : severity === 'medium' ? 'default' : 'high',
    persistent: sticky || persistentMap[severity] || false
};

if (correlation_id) data.tag   = correlation_id;
if (group)          data.group = group;
if (media?.image)   data.image = media.image;

if (url) {
    data.url = url;
    data.clickAction = url;
}            

if (actionable && actions?.length) {
    data.actions = actions.map(a => ({
        action: `${a.id.toUpperCase()}_${correlation_id}`,
        title:  a.label
    }));
}

msg.payload = {
    action: _delivery.address,
    data: { title, message, data }
};

msg.log_message = `Notification delivered to ${_delivery.recipient} via ${_delivery.channel}`;

return msg;

const notifications = global.get('config').notifications;
const { correlation_id, targets } = msg.payload;

if (!correlation_id) {
    node.warn('Clear notification dropped — missing correlation_id');
    return null;
}
if (!Array.isArray(targets) || targets.length === 0) {
    node.warn('Clear notification dropped — targets must be a non-empty array');
    return null;
}

for (const target of targets) {
    const parts = target.split('.');
    if (parts.length !== 3) {
        node.warn(`Invalid target format: ${target}`);
        continue;
    }
    const [namespace, key, channel] = parts;
    const section = notifications[namespace];
    if (!section) { node.warn(`Unknown namespace: ${namespace}`); continue; }

    const keys = key === '*' ? Object.keys(section) : [key];
    for (const k of keys) {
        const entry = section[k];
        if (!entry) { node.warn(`Unknown ${namespace} key: ${k}`); continue; }
        const address = entry.channels?.[channel];
        if (!address) { node.warn(`No channel '${channel}' for ${namespace}.${k}`); continue; }
        node.send({
            payload: {
                _delivery: { namespace, key: k, channel, address, type: 'clear' },
                correlation_id
            },
            target: resolveLinkTarget(channel)
        });
    }
}
return null;

function resolveLinkTarget(channel) {
    switch (channel) {
        case 'ha_companion': return 'Home Assistant Companion';
        case 'tv':           return 'Television Routing';
        default: throw new Error(`Unable to resolve channel: ${channel}`);
    }
}

msg.payload = {
    timestamp: new Date().toISOString(),
    system: 'node_red',
    source: 'notifications',
    level: msg.log_level || 'INFO',
    message: msg.log_message || 'Notification delivered',
    context: msg.log_context || {}
};
return msg;

const level = msg.log_level || 'INFO';
const message = msg.log_message || 'Notification delivered';

if (level === 'WARN' || level === 'ERROR') {
    node.error(`[notifications] ${message}`);
} else {
    node.warn(`[notifications] ${message}`);
}
return null;

msg.payload = {
    timestamp: new Date().toISOString(),
    source: 'test',
    targets: ['people.joseph.ha_companion'],
    severity: 'low',
    title: 'Highland Test',
    message: 'Notification pipeline test — if you can read this, it works.',
    group: 'highland_test'
};
return msg;

msg.payload = {
    timestamp: new Date().toISOString(),
    source: 'test',
    targets: ['people.joseph.ha_companion'],
    severity: 'low',
    title: 'Highland Test',
    message: 'Tagged Message Test.',
    group: 'highland_test',
    correlation_id: 'sample-tag'
};
return msg;

msg.payload = {
    targets: ['people.joseph.ha_companion'],
    correlation_id: 'sample-tag'
};
return msg;

const { _delivery } = msg.payload;

// Clear path — TV auto-dismisses
if (_delivery.type === 'clear') {
    msg.log_message = `TV clear ignored for ${_delivery.key} — auto-dismiss`;
    return [null, msg];
}

// TV off or unavailable — drop
const state = msg.data;
if (['off', 'unavailable', 'unknown'].includes(state)) {
    msg.log_message = `TV notification dropped for ${_delivery.key} — TV is ${state}`;
    return [null, msg];
}

// TV is on — route to Android TV Delivery (phase 1: no source detection)
msg.target = 'Android TV Delivery';
return [msg, null];

const { _delivery, title, message, largeIcon, smallIcon, smallIconColor, media } = msg.payload;
const { host, port } = _delivery.address.android_tv;

const body = {
    title:          title          || null,
    message:        message        || null,
    source:         'Highland Smart Home',
    largeIcon:      largeIcon      || null,
    smallIcon:      smallIcon      || null,
    smallIconColor: smallIconColor || null,
    image:          media?.image   || null,
    video:          media?.video   || null
};

// Strip null fields
Object.keys(body).forEach(k => body[k] === null && delete body[k]);

msg.payload = body;
msg.url = `http://${host}:${port}/notify`;

const formatStatus = global.get('utils.formatStatus', 'initializers');
node.status({ fill: 'blue', shape: 'dot', text: formatStatus(`→ ${_delivery.key}`) });

msg.log_message = `TvOverlay notification delivered to ${_delivery.key}`;
return msg;

const { _delivery, severity, title, message } = msg.payload;

// WebOS notify service — simple title + message overlay
msg.payload = {
    action: _delivery.address,
    data: {
        title,
        message
    }
};

msg.log_message = `WebOS notification delivered to ${_delivery.key}`;
return msg;

const state = msg.data.state;

if (['off', 'unavailable', 'unknown'].includes(state)) {
    const formatStatus = global.get('utils.formatStatus', 'initializers');
    node.status({ fill: 'grey', shape: 'dot', text: formatStatus(`STB ${state} — skipped`) });
    return [null, msg];
}

return [msg, null];

msg.payload = {
    timestamp: new Date().toISOString(),
    source: 'test',
    targets: ['areas.living_room.tv'],
    severity: 'medium',
    title: 'Highland TV Test',
    message: 'TvOverlay pipeline test — if you see this on the TV, it works.',
    icon: 'mdi:television-play',
    group: 'highland_test'
};
return msg;

const notifId = msg.payload.notification_id;
if (!notifId) return msg;

const subscriptions = global.get('config')?.notifications?.subscriptions;
if (!subscriptions) {
    node.warn('notifications.subscriptions not found in global config');
    return null;
}

const sub = subscriptions[notifId];
if (!sub) {
    node.warn(`notification_id '${notifId}' not found in subscriptions — dropped`);
    return null;
}

msg.payload = {
    ...msg.payload,
    targets:  sub.targets,
    severity: sub.severity
};
delete msg.payload.notification_id;

return msg;

const notifId = msg.payload.notification_id;
if (!notifId) return msg; // no ID — pass through unchanged

const subscriptions = global.get('config')?.notifications?.subscriptions;
if (!subscriptions) {
    node.warn('notifications.subscriptions not found in global config');
    return null;
}

const sub = subscriptions[notifId];
if (!sub) {
    node.warn(`notification_id '${notifId}' not found in subscriptions — dropped`);
    return null;
}

// Inject targets from subscription, remove notification_id
msg.payload = {
    ...msg.payload,
    targets: sub.targets
};
delete msg.payload.notification_id;

return msg;
